import Model from 'flarum/common/Model';
export default class Week extends Model {
  name = (() => Model.attribute('name'))();
  seasonId = (() => Model.attribute('seasonId'))();
  weekNumber = (() => Model.attribute('weekNumber'))();
  seasonType = (() => Model.attribute('seasonType'))();
  startDate = (() => Model.attribute('startDate'))();
  endDate = (() => Model.attribute('endDate'))();
  season = (() => Model.hasOne('season'))();
}
flarum.reg.add('resofire-picks', 'common/models/Week', Week);